fixed_code:
fn main() {
    let data = vec![255u8, 10u8, 9u8];
    let len = data.len();

    // Correctly cast to u32 first to avoid overflow
    let truncated_len: u8 = (len as u32).try_into().unwrap_or(0);

    println!("Length: {}", truncated_len);
}
